import{_ as t,a,b as o,c as n,d as r}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as i,o as d,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"افزودن OneDrive Channel","description":"","frontmatter":{},"headers":[],"relativePath":"fa/upload/onedrive.md","filePath":"fa/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"fa/upload/onedrive.md"};function p(h,e,u,m,f,b){return d(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="افزودن-onedrive-channel" tabindex="-1">افزودن OneDrive Channel <a class="header-anchor" href="#افزودن-onedrive-channel" aria-label="Permalink to &quot;افزودن OneDrive Channel&quot;">​</a></h1><h2 id="پیش-از-شروع-چه-چیزهایی-لازم-است" tabindex="-1">پیش از شروع چه چیزهایی لازم است <a class="header-anchor" href="#پیش-از-شروع-چه-چیزهایی-لازم-است" aria-label="Permalink to &quot;پیش از شروع چه چیزهایی لازم است&quot;">​</a></h2><table tabindex="0"><thead><tr><th>مورد</th><th>چرا لازم است</th></tr></thead><tbody><tr><td>Microsoft account</td><td>برای دسترسی به Microsoft admin pages و authorize کردن OneDrive</td></tr><tr><td>دامنه ImgBed شما</td><td>برای OAuth callback URL</td></tr><tr><td>App registration</td><td>برای ساخت <code>Client ID</code> و <code>Client Secret</code></td></tr><tr><td>OneDrive account</td><td>به‌عنوان محل واقعی ذخیره files</td></tr></tbody></table><h2 id="مراحل-setup" tabindex="-1">مراحل setup <a class="header-anchor" href="#مراحل-setup" aria-label="Permalink to &quot;مراحل setup&quot;">​</a></h2><h3 id="step-1-باز-کردن-microsoft-entra-id" tabindex="-1">Step 1: باز کردن Microsoft Entra ID <a class="header-anchor" href="#step-1-باز-کردن-microsoft-entra-id" aria-label="Permalink to &quot;Step 1: باز کردن Microsoft Entra ID&quot;">​</a></h3><ol><li><code>portal.azure.com</code> را باز کنید.</li><li>بالای صفحه <code>Microsoft Entra ID</code> را جست‌وجو کنید.</li><li>اگر target page در dropdown دیده نشد، انتخاب کنید:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li><code>Microsoft Entra ID</code> را باز کنید.</li><li><code>App registrations</code> را باز کنید.</li><li><code>New registration</code> را بزنید.</li></ol><h3 id="step-2-register-کردن-app" tabindex="-1">Step 2: Register کردن App <a class="header-anchor" href="#step-2-register-کردن-app" aria-label="Permalink to &quot;Step 2: Register کردن App&quot;">​</a></h3><p>در صفحه <code>New registration</code> این fields را پر کنید:</p><table tabindex="0"><thead><tr><th>Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Name</td><td>نام قابل‌تشخیص، مثل <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>بر اساس جدول پایین انتخاب کنید</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>راهنمای account type:</p><table tabindex="0"><thead><tr><th>سناریو شما</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>فقط personal OneDrive</td><td>گزینه personal Microsoft account را انتخاب کنید.</td></tr><tr><td>هم personal و هم work/school accounts</td><td>گزینه‌ای را انتخاب کنید که هر دو personal و organizational accounts را پشتیبانی کند.</td></tr><tr><td>فقط company یا school OneDrive</td><td>گزینه organizational account را انتخاب کنید.</td></tr></tbody></table><p>پس از پر کردن form، register را بزنید.</p><p><img src="'+t+'" alt="Create OneDrive app" loading="lazy"></p><h3 id="step-3-copy-کردن-app-information" tabindex="-1">Step 3: Copy کردن App Information <a class="header-anchor" href="#step-3-copy-کردن-app-information" aria-label="Permalink to &quot;Step 3: Copy کردن App Information&quot;">​</a></h3><p>پس از ساخت app، این values را از overview page copy کنید:</p><table tabindex="0"><thead><tr><th>Microsoft Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> برای organizational accounts</td></tr></tbody></table><p><img src="'+a+'" alt="Application and tenant IDs" loading="lazy"></p><h3 id="step-4-ساخت-client-secret" tabindex="-1">Step 4: ساخت Client Secret <a class="header-anchor" href="#step-4-ساخت-client-secret" aria-label="Permalink to &quot;Step 4: ساخت Client Secret&quot;">​</a></h3><ol><li><code>Certificates &amp; secrets</code> را باز کنید.</li><li><code>New client secret</code> را بزنید.</li><li>description دلخواه وارد کنید.</li><li>expiration period انتخاب کنید.</li><li>پس از ساخت، <code>Value</code> را بلافاصله copy کنید.</li></ol><p><img src="'+o+'" alt="Save client secret value" loading="lazy"></p><h3 id="step-5-افزودن-api-permissions" tabindex="-1">Step 5: افزودن API Permissions <a class="header-anchor" href="#step-5-افزودن-api-permissions" aria-label="Permalink to &quot;Step 5: افزودن API Permissions&quot;">​</a></h3><ol><li><code>API permissions</code> را باز کنید.</li><li><code>Add a permission</code> را بزنید.</li><li><code>Microsoft Graph</code> را انتخاب کنید.</li><li><code>Delegated permissions</code> را انتخاب کنید.</li><li>این permissions را اضافه کنید:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>upload files، ساخت folders و delete files</td></tr><tr><td><code>offline_access</code></td><td>اجازه می‌دهد ImgBed <code>Refresh Token</code> بگیرد</td></tr><tr><td><code>User.Read</code></td><td>خواندن account و quota information</td></tr></tbody></table><h3 id="step-6-پر-کردن-onedrive-channel-در-imgbed" tabindex="-1">Step 6: پر کردن OneDrive Channel در ImgBed <a class="header-anchor" href="#step-6-پر-کردن-onedrive-channel-در-imgbed" aria-label="Permalink to &quot;Step 6: پر کردن OneDrive Channel در ImgBed&quot;">​</a></h3><p>در Upload Settings، <code>OneDrive</code> را انتخاب کنید و این fields را پر کنید:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>نام قابل‌تشخیص، مثل <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>مقدار <code>Client Secret Value</code> که copy کردید</td></tr><tr><td>Tenant ID</td><td>بر اساس جدول پایین</td></tr><tr><td>Refresh Token</td><td>فعلاً خالی بگذارید</td></tr><tr><td>Root directory</td><td>اختیاری. پیش‌فرض <code>imgbed</code>.</td></tr><tr><td>Note</td><td>اختیاری</td></tr></tbody></table><p><img src="'+n+'" alt="Fill OneDrive channel config" loading="lazy"></p><p>روش پر کردن <code>Tenant ID</code>:</p><table tabindex="0"><thead><tr><th>Account Type انتخاب‌شده</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Personal accounts</td><td><code>consumers</code></td></tr><tr><td>Personal + organizational accounts</td><td><code>common</code></td></tr><tr><td>فقط current organization</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="step-7-گرفتن-refresh-token" tabindex="-1">Step 7: گرفتن Refresh Token <a class="header-anchor" href="#step-7-گرفتن-refresh-token" aria-label="Permalink to &quot;Step 7: گرفتن Refresh Token&quot;">​</a></h3><ol><li>در ImgBed، <code>Get Token</code> را بزنید.</li><li>وارد Microsoft account موردنظر شوید.</li><li>authorization prompt را approve کنید.</li><li>callback page یک <code>Refresh Token</code> نمایش می‌دهد.</li><li>آن را copy کنید.</li><li>به ImgBed برگردید و در field <code>Refresh Token</code> paste کنید.</li></ol><p><img src="'+r+`" alt="Copy refresh token" loading="lazy"></p><h3 id="step-8-save-کردن-channel" tabindex="-1">Step 8: Save کردن Channel <a class="header-anchor" href="#step-8-save-کردن-channel" aria-label="Permalink to &quot;Step 8: Save کردن Channel&quot;">​</a></h3><p>بعد از پر شدن همه fields، channel را save کنید.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>portal.azure.com را باز کنید</span></span>
<span class="line"><span>-&gt; Microsoft Entra ID را جست‌وجو کنید</span></span>
<span class="line"><span>-&gt; App registrations را باز کنید</span></span>
<span class="line"><span>-&gt; app جدید register کنید</span></span>
<span class="line"><span>-&gt; Name / Supported account types / Web redirect URI را پر کنید</span></span>
<span class="line"><span>-&gt; Register</span></span>
<span class="line"><span>-&gt; Application (client) ID را copy کنید</span></span>
<span class="line"><span>-&gt; callback URL را در Authentication بررسی کنید</span></span>
<span class="line"><span>-&gt; در Certificates &amp; secrets یک Client Secret بسازید</span></span>
<span class="line"><span>-&gt; در API permissions دسترسی‌ها را اضافه کنید</span></span>
<span class="line"><span>-&gt; Client ID / Client Secret / Tenant ID را در ImgBed وارد کنید</span></span>
<span class="line"><span>-&gt; Get Token را بزنید</span></span>
<span class="line"><span>-&gt; Refresh Token را از callback page copy کنید</span></span>
<span class="line"><span>-&gt; در ImgBed paste و save کنید</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Microsoft Entra app registration: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const k=i(c,[["render",p]]);export{y as __pageData,k as default};
